# Custom role in Bicep (subscription-scoped deployment)
// vmOperatorRole.bicep
targetScope = 'subscription'

var roleDefName = guid('vm-operator-role', subscription().id)

resource vmOperatorRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: roleDefName
  properties: {
    roleName: 'Virtual Machine Operator'
    description: 'Start, restart, deallocate VMs. Cannot delete or resize.'
    type: 'CustomRole'
    permissions: [
      {
        actions: [
          'Microsoft.Compute/virtualMachines/read'
          'Microsoft.Compute/virtualMachines/start/action'
          'Microsoft.Compute/virtualMachines/restart/action'
          'Microsoft.Compute/virtualMachines/deallocate/action'
          'Microsoft.Resources/subscriptions/resourceGroups/read'
          'Microsoft.Authorization/*/read'
          'Microsoft.Support/*'
        ]
        notActions: []
        dataActions: []
        notDataActions: []
      }
    ]
    assignableScopes: [ subscription().id ]
  }
}

output roleDefinitionId string = vmOperatorRole.id

# Terraform equivalent
resource "azurerm_role_definition" "vm_operator" {
  name        = "Virtual Machine Operator"
  scope       = "/subscriptions/${var.subscription_id}"
  description = "Start, restart, deallocate VMs. Cannot delete or resize."

  permissions {
    actions = [
      "Microsoft.Compute/virtualMachines/read",
      "Microsoft.Compute/virtualMachines/start/action",
      "Microsoft.Compute/virtualMachines/restart/action",
      "Microsoft.Compute/virtualMachines/deallocate/action",
      "Microsoft.Resources/subscriptions/resourceGroups/read",
      "Microsoft.Authorization/*/read",
      "Microsoft.Support/*",
    ]
    not_actions = []
  }

  assignable_scopes = ["/subscriptions/${var.subscription_id}"]
}
